const item = $input.first();
const binary = item.binary || {};

function clone(v) {
  return JSON.parse(JSON.stringify(v));
}

function tryParseJson(value) {
  if (typeof value !== 'string') return value;
  const text = value.trim();
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
}

function normalizeMessageContent(messages) {
  let idx = -1;
  for (let i = messages.length - 1; i >= 0; i--) {
    if (messages[i].role === 'user') {
      idx = i;
      break;
    }
  }

  if (idx === -1) {
    messages.push({ role: 'user', content: [] });
    idx = messages.length - 1;
  }

  if (typeof messages[idx].content === 'string') {
    messages[idx].content = [{ type: 'text', text: messages[idx].content }];
  } else if (!Array.isArray(messages[idx].content)) {
    messages[idx].content = [];
  }

  return idx;
}

let rawBody = null;
const incomingBody = item.json?.body;

// Handle JSON and multipart variants:
// 1) JSON request: body is already an object
// 2) Multipart: body may be a JSON string
// 3) Multipart nested: body = { body: "<json string>" }
if (incomingBody !== undefined && incomingBody !== null) {
  if (typeof incomingBody === 'string') {
    rawBody = tryParseJson(incomingBody);
  } else if (typeof incomingBody === 'object' && !Array.isArray(incomingBody)) {
    if (Object.prototype.hasOwnProperty.call(incomingBody, 'body')) {
      const nested = incomingBody.body;
      if (typeof nested === 'string') {
        rawBody = tryParseJson(nested);
      } else if (nested && typeof nested === 'object' && !Array.isArray(nested)) {
        rawBody = nested;
      }
    }

    if (!rawBody) {
      rawBody = incomingBody;
    }
  }
}

// 4) Multipart with binary form field named "body"
if (!rawBody && binary.body) {
  const bodyBuffer = await this.helpers.getBinaryDataBuffer(0, 'body');
  const bodyText = bodyBuffer.toString('utf8').trim();
  rawBody = tryParseJson(bodyText);
}

if (!rawBody || typeof rawBody !== 'object' || Array.isArray(rawBody)) {
  rawBody = {};
}

const messages = Array.isArray(rawBody.messages) ? clone(rawBody.messages) : [];
const userIdx = normalizeMessageContent(messages);

const attachmentKeys = Object.keys(binary).filter((k) => k !== 'body');

for (const key of attachmentKeys) {
  const bin = binary[key];
  const mime = bin.mimeType || 'application/octet-stream';
  const fileName = bin.fileName || key;
  const fileBuffer = await this.helpers.getBinaryDataBuffer(0, key);
  const base64 = fileBuffer.toString('base64');
  const dataUrl = `data:${mime};base64,${base64}`;

  if (mime.startsWith('image/')) {
    messages[userIdx].content.push({
      type: 'image_url',
      image_url: { url: dataUrl },
    });
  } else {
    messages[userIdx].content.push({
      type: 'text',
      text: `Attached file: ${fileName} (${mime}). Data URL: ${dataUrl}`,
    });
  }
}

return [{
  json: {
    ...item.json,
    body: {
      ...rawBody,
      messages,
    },
  },
}];

